	public isValidBuildingTable(table: any): boolean {
		// we want to find <tbody> node in the table
		const tbody = table.childNodes.find((child: any) => child.nodeName === "tbody");
		if (!tbody) {
			//gadak isi tabelnya
			return false;
		}
		if (!tbody.childNodes) {
			//gadak anaknya
			return false;
		}
		let hasTitleField = false;
		let hasAddressField = false;

		// iterate each <tr>
		for (const tr of tbody.childNodes) {
			if (tr.nodeName === "tr" && tr.childNodes) {
				// iterate each (<td>)
				for (const td of tr.childNodes) {
					if (td.nodeName === "td" && td.attrs) {
						// from CHATGPT
						// check if this <td> has the "views-field-title" class
						if (td.attrs.some((attr: any) => attr.name === "class" && attr.value.includes("views-field-title"))) {
							hasTitleField = true;
						}
						// check if this <td> has the "views-field-field-building-address" class
						if (
							td.attrs.some(
								(attr: any) => attr.name === "class" && attr.value.includes("views-field-field-building-address")
							)
						) {
							hasAddressField = true;
						}
					}

					if (hasTitleField && hasAddressField) {
						return true;
					}
				}
			}
		}

		return false;
	}

	public async getRoomFilePath(zipData: JSZip, link: string): Promise<string> {
		// from ChatGPT
		const num = 2;
		const adjustedLink = link.startsWith("./") ? link.slice(num) : link;
		return Object.keys(zipData.files).find((path) => path.endsWith(adjustedLink)) || adjustedLink;
	}

	public async extractRoom(roomTable: any, building: any): Promise<any[]> {
		const rooms: any[] = [];
		const tbody = roomTable.childNodes.find((child: any) => child.nodeName === "tbody");

		for (const tr of tbody.childNodes) {
			if (tr.nodeName === "tr" && tr.childNodes) {
				const roomData: any = {
					fullname: building.fullname,
					shortname: building.shortname,
					address: building.address,
					lat: building.lat,
					lon: building.lon,
				};

				for (const td of tr.childNodes) {
					if (td.nodeName === "td" && td.attrs) {
						this.getRoomAttribute(td, roomData);
					}
				}
				roomData.name = `${roomData.shortname}_${roomData.number}`;
				if (Object.keys(roomData).length > 0) {
					rooms.push(roomData);
				}
			}
		}
		return rooms;
	}

	public getRoomAttribute(td: any, roomData: any): void {
		const classAttr = td.attrs.find((attr: any) => attr.name === "class");
		if (classAttr) {
			if (classAttr.value.includes("views-field views-field-field-room-number")) {
				roomData.number = td.childNodes[1].childNodes[0]?.value.trim();
				//console.log(roomData.number);
			} else if (classAttr.value.includes("views-field views-field-field-room-capacity")) {
				roomData.seats = parseInt(td.childNodes[0]?.value.trim(), 10);
			} else if (classAttr.value.includes("views-field views-field-field-room-furniture")) {
				roomData.furniture = td.childNodes[0]?.value.trim();
				//console.log(roomData.furniture);
			} else if (classAttr.value.includes("views-field views-field-field-room-type")) {
				roomData.type = td.childNodes[0]?.value.trim();
			} else if (classAttr.value.includes("views-field views-field-nothing")) {
				const link = td.childNodes.find((node: any) => node.nodeName === "a");
				if (link?.attrs) {
					const hrefAttr = link.attrs.find((attr: any) => attr.name === "href");
					if (hrefAttr) {
						roomData.href = hrefAttr.value;
					}
				}
			}
		}
	}

	public isValidRoomTable(table: any): boolean {
		const tbody = table.childNodes.find((child: any) => child.nodeName === "tbody");
		if (!tbody?.childNodes) {
			return false;
		}
		let hasRoomNumber = false;
		let hasCapacity = false;
		let hasFurniture = false;
		let hasRoomType = false;

		for (const tr of tbody.childNodes) {
			if (tr.nodeName === "tr" && tr.childNodes) {
				for (const td of tr.childNodes) {
					if (td.nodeName === "td" && td.attrs) {
						const classAttr = td.attrs.find((attr: any) => attr.name === "class");
						if (classAttr) {
							hasRoomNumber ||= this.hasField(classAttr, "views-field views-field-field-room-number");
							hasCapacity ||= this.hasField(classAttr, "views-field views-field-field-room-capacity");
							hasFurniture ||= this.hasField(classAttr, "views-field views-field-field-room-furniture");
							hasRoomType ||= this.hasField(classAttr, "views-field views-field-field-room-type");
						}

						// If we have all indicators, we’ve found a valid room table
						if (hasRoomNumber && hasCapacity && hasFurniture && hasRoomType) {
							return true;
						}
					}
				}
			}
		}
		return false;
	}

	public processBuildingRow(row: any, buildingLinks: string[]): any {
		const buildingData: any = {};

		for (const td of row.childNodes) {
			if (td.nodeName === "td" && td.attrs) {
				const classAttr = td.attrs.find((attr: any) => attr.name === "class")?.value;

				if (classAttr) {
					if (classAttr.includes("views-field-title")) {
						const linkElement = td.childNodes.find((node: any) => node.nodeName === "a");
						const hrefAttr = linkElement?.attrs?.find((attr: any) => attr.name === "href")?.value;
						if (hrefAttr) {
							buildingLinks.push(hrefAttr);
						}
						buildingData.fullname = linkElement?.childNodes[0]?.value.trim();
					} else if (classAttr.includes("views-field-field-building-code")) {
						buildingData.shortname = td.childNodes[0]?.value.trim();
					} else if (classAttr.includes("views-field-field-building-address")) {
						buildingData.address = td.childNodes[0]?.value.trim();
					}
				}
			}
		}
		return buildingData;
	}

	public hasField(classAttr: any, fieldName: string): boolean {
		return classAttr.value.includes(fieldName);
	}

	public findAllNodesByName(node: any, name: string): any[] {
		const nodes: any[] = [];
		// base case
		if (node.nodeName === name) {
			nodes.push(node);
		}
		// recursively search the node
		if (node.childNodes) {
			for (const child of node.childNodes) {
				nodes.push(...this.findAllNodesByName(child, name));
			}
		}
		return nodes;
	}

	public extractBuildingsData(buildingTable: any): { buildings: any[]; buildingLinks: string[] } {
		const buildings: any[] = [];
		const buildingLinks: string[] = [];

		const tbody = buildingTable.childNodes.find((node: any) => node.nodeName === "tbody");
		if (!tbody) {
			throw new InsightError("invalid tbody in table");
		}

		for (const tr of tbody.childNodes) {
			if (tr.nodeName === "tr" && tr.childNodes) {
				const buildingData = this.processBuildingRow(tr, buildingLinks);
				if (Object.keys(buildingData).length > 0) {
					buildings.push(buildingData);
				}
			}
		}
		return { buildings, buildingLinks };
	}

	public async assignLatLon(buildings: any[]): Promise<void> {
		//let i =0;
		const geolocationPromises = buildings.map(async (building) => {
			//console.log(building.address);
			const geolocation = await this.getGeolocation(building.address);
			//console.log(geolocation);
			//i++;
			if (geolocation.lat !== undefined || geolocation.lon !== undefined) {
				building.lat = geolocation.lat;
				building.lon = geolocation.lon;
			} else {
				throw new InsightError("no geo");
			}
		});
		//console.log(i);
		await Promise.all(geolocationPromises);
	}

	public async getGeolocation(address: string): Promise<any> {
		// const http = require("node:http");
		return new Promise((resolve, reject) => {
			const encodedAddress = encodeURIComponent(address);
			const url = `http://cs310.students.cs.ubc.ca:11316/api/v1/project_team139/${encodedAddress}`;

			http
				.get(url, (res) => {
					let data = "";
					res.on("data", (chunk) => {
						data += chunk;
					});

					const successful = 200;
					res.on("end", () => {
						if (res.statusCode === successful) {
							try {
								const json = JSON.parse(data);
								resolve(json);
							} catch (_error) {
								reject(new InsightError("Failed to parse response"));
							}
						} else {
							reject(new InsightError("Failed to parse response"));
						}
					});
				})
				.on("error", (error) => {
					reject(error);
				});
		});
	}
}

import { InsightError } from "./IInsightFacade";
import { Section, Room } from "./helperClass";
import { HelperFunction } from "./helperFunction";

export class HelperWhere {
	private hf = new HelperFunction();

	public async handleWhere(where: any, sections: Section[] | Room[], queryId: string): Promise<Section[] | Room[]> {
		// base case
		if (Object.keys(where).length === 0) {
			return sections;
		}
		if (where.AND || where.OR) {
			// handle logic comp
			return await this.handleLogicComp(where, sections, queryId);
		}
		if (where.NOT) {
			return await this.handleNegation(where, sections, queryId);
		}
		if (where.IS) {
			return await this.handleSComp(where, sections, queryId);
		}
		if (where.LT || where.GT || where.EQ) {
			return await this.handleMComp(where, sections, queryId);
		}

		throw new InsightError("invalid ebnf");
	}

	private async handleMComp(where: any, sections: Section[] | Room[], queryId: string): Promise<Section[] | Room[]> {
		// now we have list of sections with ID that we want
		if (where.GT) {
			return await this.hf.handleGreaterThan(where, sections, queryId);
		}
		if (where.LT) {
			return await this.hf.handleLessThan(where, sections, queryId);
		}

		if (where.EQ) {
			return await this.hf.handleEqual(where, sections, queryId);
		}
		throw new InsightError("no m comp");
	}

	private async handleSComp(where: any, sections: Section[] | Room[], queryId: string): Promise<Section[] | Room[]> {
		if (Object.keys(where.IS).length === 0) {
			throw new InsightError("Invalid Query Syntax for IS");
		}

		const [key, value]: [string, unknown] = Object.entries(where.IS)[0];
		const param = key.split("_")[1];
		const dataset = key.split("_")[0];
		if (dataset !== queryId) {
			throw new InsightError("");
		}

		if (typeof value !== "string") {
			throw new InsightError("invalid skey");
		}
		let a: Section[] | Room[] = [];

		if (this.hf.isSectionArray(sections)) {
			a = sections.filter((s: Section) => {
				const valueType = this.hf.getValueType(value);
				const compareValue = this.hf.getParamString(param, s);
				if (valueType === "startend") {
					const newString = value.slice(1, -1);
					return compareValue.includes(newString);
				} else if (valueType === "start") {
					const newString = value.slice(1);
					// console.log(newString);
					return compareValue.endsWith(newString);
				} else if (valueType === "end") {
					const newString = value.slice(0, -1);
					return compareValue.startsWith(newString);
				} else {
					return compareValue === value;
				}
			}) as Section[];
		} else if (this.hf.isRoomArray(sections)) {
			a = sections.filter((s: Room) => {
				const valueType = this.hf.getValueType(value);
				const compareValue = this.hf.getParamString(param, s);
				if (valueType === "startend") {
					const newString = value.slice(1, -1);
					return compareValue.includes(newString);
				} else if (valueType === "start") {
					const newString = value.slice(1);
					// console.log(newString);
					return compareValue.endsWith(newString);
				} else if (valueType === "end") {
					const newString = value.slice(0, -1);
					return compareValue.startsWith(newString);
				} else {
					return compareValue === value;
				}
			}) as Room[];
		}

		return a;
	}

	private async handleLogicComp(
		where: any,
		sections: Section[] | Room[],
		queryId: string
	): Promise<Section[] | Room[]> {
		// where.LOGIC is an array, e.g. ( { AND: [ { GT: [Object] }, { IS: [Object] } ] } )
		// therefore filteredSections in handleOr and handleAnd stores the result of each recursion of each branches inside the where.LOGIC

		if (where.OR) {
			return this.handleOr(where, sections, queryId);
		}

		if (where.AND) {
			return this.handleAnd(where, sections, queryId);
		}

		throw new InsightError(`Invalid logical operator: ${where[0]}`);
	}

	private async handleOr(where: any, sections: Section[] | Room[], queryId: string): Promise<Section[] | Room[]> {
		if (where.OR.length === 0) {
			throw new InsightError("Invalid Query Syntax");
		}

		const orPromises = where.OR.map(async (condition: any) => this.handleWhere(condition, sections, queryId));

		const filteredSections = await Promise.all(orPromises);

		const flattenedSections = filteredSections.flat();

		if (this.hf.isSectionArray(flattenedSections) && this.hf.isSectionArray(sections)) {
			return sections.filter((s: Section) => flattenedSections.includes(s));
		} else if (this.hf.isRoomArray(flattenedSections) && this.hf.isRoomArray(sections)) {
			return sections.filter((s: Room) => flattenedSections.includes(s));
		}
		throw new InsightError("invalid kind");
	}

	private async handleAnd(where: any, sections: Section[] | Room[], queryId: string): Promise<Section[] | Room[]> {
		if (where.AND.length === 0) {
			throw new InsightError("Invalid Query Syntax");
		}

		const andPromises = where.AND.map(async (condition: any) => this.handleWhere(condition, sections, queryId));

		const filteredSections = await Promise.all(andPromises);

		if (this.hf.isSectionArray(sections)) {
			return sections.filter((section) =>
				filteredSections.every((filtered) => filtered.includes(section))
			) as Section[];
		} else if (this.hf.isRoomArray(sections)) {
			return sections.filter((section) => filteredSections.every((filtered) => filtered.includes(section))) as Room[];
		}

		throw new InsightError("no valid kind");
		//return sections.filter((section) => filteredSections.every((filtered) => filtered.includes(section))) as Section[] | Room[];
	}

	private async handleNegation(where: any, sections: Section[] | Room[], queryId: string): Promise<Section[] | Room[]> {
		const filteredSections = await this.handleWhere(where.NOT, sections, queryId);
		if (this.hf.isSectionArray(filteredSections) && this.hf.isSectionArray(sections)) {
			return sections.filter((s: Section) => {
				return !filteredSections.includes(s);
			}) as Section[];
		} else if (this.hf.isRoomArray(filteredSections) && this.hf.isRoomArray(sections)) {
			return sections.filter((s: Room) => {
				return !filteredSections.includes(s);
			}) as Room[];
		}
		return [];
	}
}

import { InsightError, InsightResult } from "./IInsightFacade";
import { Room, Section } from "./helperClass";
import { HelperFunction } from "./helperFunction";
import { HelperSort } from "./helperSort";

